# 输入获取
arr = list(map(int, input().split()))


def dfs(arr, root, res):
    left = root * 2 + 1
    right = root * 2 + 2

    if len(arr) > left:
        dfs(arr, left, res)
        if len(arr) > right:
            dfs(arr, right, res)
        res.append(arr[root])


# 算法入口
def getResult():
    if len(arr) == 1:
        return arr[0]

    res = []
    dfs(arr, 0, res)

    return " ".join(map(str, res))


# 算法调用
print(getResult())
